#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define ull unsigned long long
#define inf 0x3f3f3f3f
#define NoAns puts("-1")
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN=1e5+5;
int n, ans = inf;
int a[MAXN];
int main(void)
{
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
    cin>>n;
    for (int i = 1; i <= n; ++i)cin>>a[i];
    sort(a+1,a+n+1);
    for (int j = a[1]; j <= a[n]; ++j)
    {
    	int tmp=0;
        for (int i = 1; i <= n; ++i)
        {
            if (a[i] < j - 17) tmp += (j - a[i] - 17) * (j - a[i] - 17);
            if (a[i] > j) tmp += (a[i] - j) * (a[i] - j);
        }
        ans = min(ans, tmp);
    }
    cout<<ans;
    return false;
}
